use strict;
use warnings;
use Storable;

# File path to store sessions
my $session_file_path = '/tmp/sessions';

sub create_session {
    my ($session_data) = @_;
    
    # Generate session ID
    my $session_id = join(':', uniqid(), rand);
    
    # Serialize and store in file
    store($session_data, "$session_file_path/$session_id");
}

sub load_session {
    my ($session_id) = @_;
    
    return retrieve("$session_file_path/$session_id") if -e "$session_file_path/$session_id";
    return undef;
}

sub get_session {
    my ($session_id) = @_;
    
    my $session_data = load_session($session_id);
    
    # Session is valid for 30 minutes
    if (defined $session_data && time() - (60*30) > -e "$session_file_path/$session_id") {
        return undef;
    }
    
    return $session_data;
}

sub destroy_session {
    my ($session_id) = @_;
    
    unlink("$session_file_path/$session_id");
}

